if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const body = $input.first().json.body || $input.first().json;
const query = body.query || body.question || body.message;
const top_k = body.top_k || 5;
if (!query) { throw new Error('query is required'); }
return [{ json: { query, top_k } }];

const query = $('Validate Query').first().json.query;
const matches = $json.matches || [];
if (matches.length === 0) {
  return [{ json: { query, context: '', sources: [], has_results: false } }];
}
const sources = [];
const chunks = [];
for (const m of matches) {
  const meta = m.metadata || {};
  chunks.push(meta.text || '');
  if (meta.document_id && !sources.includes(meta.document_id)) sources.push(meta.document_id);
}
return [{ json: { query, context: chunks.join('\n\n---\n\n'), sources, has_results: true } }];

const query = $('Validate Query').first().json.query;
const sources = $('Build Context').first().json.sources;
const raw = $json.content?.[0]?.text || $json.content || '';
let parsed = {};
try {
  const match = typeof raw === 'string' ? raw.match(/\{[\s\S]*\}/) : null;
  if (match) parsed = JSON.parse(match[0]);
  else parsed = { answer: typeof raw === 'string' ? raw : JSON.stringify(raw) };
} catch(e) {
  parsed = { answer: typeof raw === 'string' ? raw : JSON.stringify(raw) };
}
return [{ json: {
  answer: parsed.answer || 'No answer generated',
  sources: parsed.sources || sources,
  confidence: parsed.confidence || 'medium',
  query,
  timestamp: new Date().toISOString()
}}];

// Reshape pgvector response to Pinecone-compatible matches shape
const pgResponse = $input.first().json;
const results = (pgResponse.data || {}).results || pgResponse.results || [];
const matches = results.map(r => ({
  id: r.id,
  score: r.similarity,
  metadata: {
    text: r.chunk_text || '',
    chunk_text: r.chunk_text || '',
    document_id: r.document_id || '',
    chunk_index: r.chunk_index || 0,
    page_number: r.page_number || null,
    page: r.page_number || null,
    section_title: r.section_title || null,
    source: (r.metadata || {}).source || 'unknown',
    file_name: (r.metadata || {}).file_name || r.document_id || 'unknown',
    filename: (r.metadata || {}).file_name || r.document_id || 'unknown',
    file_type: (r.metadata || {}).file_type || 'unknown',
    classification: (r.metadata || {}).classification || 'UNCLASSIFIED',
    ...(r.metadata || {})
  }
}));
return [{ json: { matches } }];
